import { useState, useEffect, useRef } from 'react'
import { getAlumnosByGrade } from '@/services/alumnos'
import { Alumno } from '@/services/alumnos'
import {
  getColegioSettings,
  ColegioSettings,
} from '@/services/colegio-settings'
import { getGradeByDirector } from '@/services/grade-directors'
import { GradeDirectorInfo } from '@/services/grade-directors'
import { getSubjectsByGrade, GradeSubject } from '@/services/grade-subjects'
import {
  getSubmittedReportsForStudent,
  QualitativeReport,
} from '@/services/qualitative-reports'
import {
  Users,
  FileText,
  BookOpen,
  ChevronLeft,
  Download,
  Loader2,
} from 'lucide-react'
import { toast } from 'sonner'
import { useAuth } from '@/hooks/use-auth'
import { useColegio } from '@/hooks/use-colegio'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Separator } from '@/components/ui/separator'
import { Textarea } from '@/components/ui/textarea'
import { ProtectedRoute } from '@/components/ProtectedRoute'
import { Header } from '@/components/layout/header'
import { Main } from '@/components/layout/main'
import { ProfileDropdown } from '@/components/profile-dropdown'
import { Search } from '@/components/search'

// Logo base64 del colegio
// INSTRUCCIONES: Reemplaza las comillas vacías con tu imagen en base64
// Opción 1: Pega aquí el código base64 completo (empieza con 'data:image/png;base64,iVBORw0K...')
// Opción 2: Deja vacío si no tienes logo aún
const LOGO_BASE64 =
  'data:image/png;base64,'
//
// Para convertir tu logo a base64:
// 1. Ve a https://www.base64-image.de/
// 2. Sube tu imagen del escudo/logo
// 3. Copia el código generado (el que empieza con 'data:image/')
// 4. Pégalo entre las comillas de arriba

interface SubjectObservation {
  subjectId: string
  subjectName: string
  pendingActivities: string
  insufficientActivities: string
  positiveNotes: string
  teacherObservation: string
  behavioralIssues: 'Sí' | 'No'
  attendanceIssues: 'Sí' | 'No'
  personalPresentation: string
}

interface StudentReport {
  student: Alumno
  subjects: GradeSubject[]
  observations: SubjectObservation[]
  generalObservations: string
}

export function IndividualStudentReportPage() {
  const { user, isDocente } = useAuth()
  const { selectedColegio } = useColegio()

  // Estados para la carga de datos
  const [isLoading, setIsLoading] = useState(true)
  const [isDirector, setIsDirector] = useState(false)
  const [managedGrade, setManagedGrade] = useState<GradeDirectorInfo | null>(
    null
  )
  const [students, setStudents] = useState<Alumno[]>([])
  const [colegioSettings, setColegioSettings] =
    useState<ColegioSettings | null>(null)

  // Estados para la selección y el formulario
  const [selectedStudent, setSelectedStudent] = useState<Alumno | null>(null)
  const [selectedPeriod, setSelectedPeriod] = useState<string>('1')
  const [report, setReport] = useState<StudentReport | null>(null)
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false)
  const [gradeSubjects, setGradeSubjects] = useState<GradeSubject[]>([])

  // Track if we've already loaded to prevent re-loading
  const hasLoaded = useRef(false)

  // Cargar el grado del director y estudiantes al montar
  useEffect(() => {
    // Only load once when user name is available and we haven't loaded yet
    if (user?.name && isDocente && !hasLoaded.current) {
      hasLoaded.current = true
      loadDirectorGrade()
    }
  }, [user?.name, isDocente])

  const loadDirectorGrade = async () => {
    if (!user?.name) return

    setIsLoading(true)
    const startTime = Date.now()

    try {
      // Verificar si el docente es director de algún grado
      const grade = await getGradeByDirector(
        user.name,
        selectedColegio || undefined
      )

      if (grade) {
        setIsDirector(true)
        setManagedGrade(grade)

        // Cargar estudiantes del grado en paralelo con la configuración
        const colegioId = selectedColegio || grade.colegio_id || '1'

        const [studentsData, subjectsData] = await Promise.all([
          getAlumnosByGrade(grade.id, colegioId),
          getSubjectsByGrade(grade.id, colegioId),
          // Precargar configuración pero no bloquear
          selectedColegio
            ? getColegioSettings(selectedColegio)
                .then(setColegioSettings)
                .catch(() => {})
            : Promise.resolve(),
        ])

        setStudents(studentsData)
        setGradeSubjects(subjectsData)
      } else {
        setIsDirector(false)
      }
    } catch (error) {
      console.error('Error loading director grade:', error)
      toast.error('Error al cargar la información del director de grado')
    } finally {
      // Ensure loading shows for at least 300ms to prevent flicker
      const elapsed = Date.now() - startTime
      if (elapsed < 300) {
        await new Promise((resolve) => setTimeout(resolve, 300 - elapsed))
      }
      setIsLoading(false)
    }
  }

  // Manejar selección de estudiante
  const handleSelectStudent = async (student: Alumno) => {
    setSelectedStudent(student)
    setIsLoading(true)

    try {
      // Cargar los informes enviados por los docentes para este estudiante
      console.log(
        'Loading reports for student:',
        student.id,
        'period:',
        selectedPeriod
      )
      const submittedReports = await getSubmittedReportsForStudent(
        student.id,
        parseInt(selectedPeriod)
      )
      console.log(
        'Submitted reports received:',
        submittedReports.length,
        submittedReports
      )

      // Crear un mapa de informes por materia
      const reportsBySubject = new Map<string, QualitativeReport>()
      submittedReports.forEach((report) => {
        console.log('Processing report:', report)
        // Intentar obtener el subject_id de diferentes fuentes
        const subjectId = report.subject?.id || (report as any).subject_id
        if (subjectId) {
          reportsBySubject.set(subjectId, report)
          console.log(
            'Added report for subject:',
            subjectId,
            report.subject?.name || 'Unknown'
          )
        } else {
          console.log('Report without subject ID:', report)
        }
      })

      // Inicializar las observaciones para cada materia con los datos recibidos
      console.log('Grade subjects:', gradeSubjects)
      const observations: SubjectObservation[] = gradeSubjects.map((item) => {
        console.log(
          'Looking for report for subject:',
          item.subject.id,
          item.subject.name
        )
        const submittedReport = reportsBySubject.get(item.subject.id)
        console.log('Found report:', submittedReport)

        // Parsear las actividades de los JSON strings
        let pendingActivities = ''
        let insufficientActivities = ''
        let positiveNotes = ''

        if (submittedReport) {
          try {
            // Parsear actividades no entregadas
            if (submittedReport.activities_not_delivered) {
              const activities = JSON.parse(
                submittedReport.activities_not_delivered
              )
              pendingActivities = activities
                .map((a: any) => {
                  // Formato: tipo: nombre (fecha)
                  const activityType =
                    a.activity_type || a.category || 'Actividad'
                  const date = a.created_at || ''
                  return date
                    ? `${activityType}: ${a.name} (${date})`
                    : `${activityType}: ${a.name}`
                })
                .join('\n')
            }

            // Parsear actividades insuficientes
            if (submittedReport.insufficient_activities) {
              const activities = JSON.parse(
                submittedReport.insufficient_activities
              )
              insufficientActivities = activities
                .map((a: any) => {
                  // Formato: tipo: nombre (nota)
                  const activityType =
                    a.activity_type || a.category || 'Actividad'
                  const grade = a.grade !== undefined ? a.grade : ''
                  if (grade !== '') {
                    // Formatear la nota con un decimal
                    const gradeNum =
                      typeof grade === 'number' ? grade : parseFloat(grade)
                    const formattedGrade = isNaN(gradeNum)
                      ? grade
                      : gradeNum.toFixed(1)
                    return `${activityType}: ${a.name} (${formattedGrade})`
                  }
                  return `${activityType}: ${a.name}`
                })
                .join('\n')
            }

            // Parsear notas positivas
            if (submittedReport.positive_notes) {
              const activities = JSON.parse(submittedReport.positive_notes)
              positiveNotes = activities
                .map((a: any) => {
                  // Formato: tipo: nombre (nota)
                  const activityType =
                    a.activity_type || a.category || 'Actividad'
                  const grade = a.grade !== undefined ? a.grade : ''
                  if (grade !== '') {
                    // Formatear la nota con un decimal
                    const gradeNum =
                      typeof grade === 'number' ? grade : parseFloat(grade)
                    const formattedGrade = isNaN(gradeNum)
                      ? grade
                      : gradeNum.toFixed(1)
                    return `${activityType}: ${a.name} (${formattedGrade})`
                  }
                  return `${activityType}: ${a.name}`
                })
                .join('\n')
            }

            // Parsear notas positivas
            if (submittedReport.positive_notes) {
              const activities = JSON.parse(submittedReport.positive_notes)
              positiveNotes = activities
                .map((a: any) => {
                  // Formato: tipo: nombre (nota)
                  const activityType =
                    a.activity_type || a.category || 'Actividad'
                  const grade = a.grade !== undefined ? a.grade : ''
                  return grade !== ''
                    ? `${activityType}: ${a.name} (${grade})`
                    : `${activityType}: ${a.name}`
                })
                .join('\n')
            }
          } catch (e) {
            console.error('Error parsing activities:', e)
          }
        }

        return {
          subjectId: item.subject.id,
          subjectName: item.subject.name,
          pendingActivities: pendingActivities || '',
          insufficientActivities: insufficientActivities || '',
          positiveNotes: positiveNotes || '',
          teacherObservation: submittedReport?.observations || '',
          behavioralIssues: submittedReport?.behavioral_issues || 'No',
          attendanceIssues: submittedReport?.attendance_issues || 'No',
          personalPresentation: submittedReport?.personal_presentation || '',
        }
      })

      // Inicializar el reporte con las materias del grado
      setReport({
        student,
        subjects: gradeSubjects,
        observations,
        generalObservations: '',
      })
    } catch (error) {
      console.error('Error loading student reports:', error)
      toast.error('Error al cargar los informes del estudiante')

      // En caso de error, inicializar con valores vacíos
      const observations: SubjectObservation[] = gradeSubjects.map((item) => ({
        subjectId: item.subject.id,
        subjectName: item.subject.name,
        pendingActivities: '',
        insufficientActivities: '',
        positiveNotes: '',
        teacherObservation: '',
        behavioralIssues: 'No',
        attendanceIssues: 'No',
        personalPresentation: '',
      }))

      setReport({
        student,
        subjects: gradeSubjects,
        observations,
        generalObservations: '',
      })
    } finally {
      setIsLoading(false)
    }
  }

  // Volver a la lista de estudiantes
  const handleBackToStudents = () => {
    setSelectedStudent(null)
    setReport(null)
  }

  // Actualizar observaciones de una materia específica
  const handleUpdateSubjectObservation = (
    subjectId: string,
    field: keyof Omit<SubjectObservation, 'subjectId' | 'subjectName'>,
    value: string
  ) => {
    if (!report) return
    const updatedObservations = report.observations.map((obs) =>
      obs.subjectId === subjectId ? { ...obs, [field]: value } : obs
    )
    setReport({ ...report, observations: updatedObservations })
  }

  // Verificar si hay informes para el estudiante en el período seleccionado
  const handlePeriodChange = async (newPeriod: string) => {
    setSelectedPeriod(newPeriod)
    if (selectedStudent) {
      // Recargar los datos del estudiante con el nuevo período
      await handleSelectStudent(selectedStudent)
    }
  }

  // Guardar reporte (podría conectarse a una API en el futuro)
  const handleSaveReport = () => {
    // Aquí se podría guardar en la base de datos
    toast.success('Informe guardado correctamente')
  }

  // Generar PDF del informe individual
  const handleGeneratePDF = async () => {
    if (!report || !selectedStudent || !managedGrade) return

    setIsGeneratingPDF(true)
    try {
      const [{ jsPDF }, autoTable] = await Promise.all([
        import('jspdf'),
        import('jspdf-autotable'),
      ])

      const doc = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4',
      })

      // Configurar fuente
      doc.setFont('helvetica', 'normal')

      // Obtener la función autoTable
      const autoTableFn = (autoTable as any).default || autoTable

      // === ENCABEZADO MANUAL CON 4 CELDAS ===
      const today = new Date()
      const fechaStr = today.toLocaleDateString('es-ES', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
      })

      // Definir dimensiones del encabezado
      const headerStartX = 10
      const headerStartY = 8
      const headerWidth = 190
      const headerHeight = 45
      const halfWidth = headerWidth / 2
      const halfHeight = headerHeight / 2

      // Dibujar bordes exteriores
      doc.setDrawColor(0)
      doc.setLineWidth(0.5)
      doc.rect(headerStartX, headerStartY, headerWidth, headerHeight)

      // Línea vertical del medio
      doc.line(
        headerStartX + halfWidth,
        headerStartY,
        headerStartX + halfWidth,
        headerStartY + headerHeight
      )

      // Línea horizontal del medio
      doc.line(
        headerStartX,
        headerStartY + halfHeight,
        headerStartX + headerWidth,
        headerStartY + halfHeight
      )

      // === CELDA 1: Colegio y Lema (arriba-izquierda) ===
      doc.setFontSize(14)
      doc.setFont('helvetica', 'bold')
      doc.text(
        'COLEGIO PATRICIO SYMES',
        headerStartX + halfWidth / 2,
        headerStartY + 12,
        { align: 'center' }
      )

      doc.setFontSize(10)
      doc.setFont('helvetica', 'italic')
      doc.text(
        '"Mi enseñanza goteara como la lluvia"',
        headerStartX + halfWidth / 2,
        headerStartY + 20,
        { align: 'center' }
      )

      // === CELDA 2: Logo (arriba-derecha) ===
      // Centro de la celda superior derecha
      const cell2CenterX = headerStartX + halfWidth + halfWidth / 2 // 10 + 95 + 47.5 = 152.5
      const cell2CenterY = headerStartY + halfHeight / 2 // 8 + 11.25 = 19.25
      const logoWidth = 22
      const logoHeight = 20

      if (LOGO_BASE64) {
        try {
          // Posicionar el logo centrado en la celda
          doc.addImage(
            LOGO_BASE64,
            'PNG',
            cell2CenterX - logoWidth / 2, // Centrado horizontalmente
            cell2CenterY - logoHeight / 2, // Centrado verticalmente
            logoWidth,
            logoHeight
          )
        } catch (e) {
          console.error('Error adding logo:', e)
        }
      }

      // === CELDA 3: Informe y Año (abajo-izquierda) ===
      doc.setFontSize(10)
      doc.setFont('helvetica', 'bold')
      doc.text(
        'INFORME PRELIMINAR ESTUDIANTES',
        headerStartX + halfWidth / 2,
        headerStartY + halfHeight + 10,
        { align: 'center' }
      )
      doc.text(
        'AÑO LECTIVO 2026',
        headerStartX + halfWidth / 2,
        headerStartY + halfHeight + 18,
        { align: 'center' }
      )

      // === CELDA 4: Fecha y Período (abajo-derecha) ===
      doc.setFontSize(9)
      doc.setFont('helvetica', 'normal')
      doc.text(
        `FECHA: ${fechaStr}`,
        headerStartX + halfWidth + halfWidth / 2,
        headerStartY + halfHeight + 8,
        { align: 'center' }
      )
      doc.text(
        `Corte ${selectedPeriod}º Período.`,
        headerStartX + halfWidth + halfWidth / 2,
        headerStartY + halfHeight + 16,
        { align: 'center' }
      )

      // === INFORMACIÓN DEL ESTUDIANTE ===
      doc.setFontSize(10)
      doc.setFont('helvetica', 'bold')
      doc.text('Estudiante:', 10, 60)
      doc.setFont('helvetica', 'normal')
      doc.text(
        `${selectedStudent.name} ${selectedStudent.last_name}`.toUpperCase(),
        40,
        60
      )

      doc.setFont('helvetica', 'bold')
      doc.text('Grado:', 110, 60)
      doc.setFont('helvetica', 'normal')
      doc.text(managedGrade.name, 130, 60)

      // === TABLA DE MATERIAS ===
      // Preparar datos para la tabla
      const tableData = report.observations.map((obs) => [
        obs.subjectName,
        obs.pendingActivities || '',
        obs.insufficientActivities || '',
        obs.positiveNotes || '',
      ])

      // Usar autoTable para crear la tabla (después del encabezado)
      autoTableFn(doc, {
        head: [
          [
            {
              content: 'ASIGNATURA',
              styles: { halign: 'center', fontStyle: 'bold' },
            },
            {
              content: 'ACTIVIDADES PENDIENTES',
              styles: { halign: 'center', fontStyle: 'bold' },
            },
            {
              content: 'ACTIVIDADES INSUFICIENTES',
              styles: { halign: 'center', fontStyle: 'bold' },
            },
            {
              content: 'NOTAS POSITIVAS',
              styles: { halign: 'center', fontStyle: 'bold' },
            },
          ],
        ],
        body: tableData,
        startY: 65,
        theme: 'grid',
        styles: {
          fontSize: 8,
          cellPadding: 2,
          overflow: 'linebreak',
          valign: 'top',
          lineWidth: 0.3,
          lineColor: [0, 0, 0],
        },
        headStyles: {
          fillColor: [255, 255, 255],
          textColor: [0, 0, 0],
          fontSize: 9,
          fontStyle: 'bold',
          lineWidth: 0.3,
          lineColor: [0, 0, 0],
        },
        columnStyles: {
          0: { cellWidth: 50, fontStyle: 'bold' },
          1: { cellWidth: 45 },
          2: { cellWidth: 45 },
          3: { cellWidth: 45 },
        },
        margin: { top: 65, right: 10, bottom: 40, left: 10 },
      })

      // Obtener la posición final de la tabla
      const finalY = (doc as any).lastAutoTable?.finalY || 180

      // === OBSERVACIONES/ACTITUDINAL ===
      let currentY = finalY + 10

      doc.setFontSize(10)
      doc.setFont('helvetica', 'bold')
      doc.text('OBSERVACIONES/ ACTITUDINAL', 10, currentY)
      currentY += 8

      // Líneas para observaciones
      doc.setFont('helvetica', 'normal')
      doc.setDrawColor(0)
      for (let i = 0; i < 3; i++) {
        doc.line(10, currentY, 200, currentY)
        currentY += 8
      }

      // === FIRMAS ===
      currentY += 20

      doc.setFontSize(10)
      doc.setFont('helvetica', 'bold')
      doc.setLineWidth(0.3)
      doc.setDrawColor(0)

      // Texto base
      const startX = 15
      const lineY = currentY + 1

      // === Director de Grupo ===
      const dirText = 'DIRECTOR DE GRUPO: '
      doc.text(dirText, startX, currentY)

      // Línea de firma del director
      const dirLineStart = startX + doc.getTextWidth(dirText)
      doc.line(dirLineStart, lineY, dirLineStart + 35, lineY)

      // === Firma Padre de Familia ===
      const padreText = ' FIRMA PADRE DE FAMILIA: '
      const padreTextX = dirLineStart + 35 + 5 // 5mm de espacio después de la primera línea
      doc.text(padreText, padreTextX, currentY)

      // Línea de firma del padre (más corta)
      const padreLineStart = padreTextX + doc.getTextWidth(padreText)
      doc.line(padreLineStart, lineY, padreLineStart + 35, lineY)

      // Guardar PDF
      const fileName = `informe_individual_${selectedStudent.last_name}_${selectedStudent.name}_periodo${selectedPeriod}.pdf`
      doc.save(fileName)

      toast.success('PDF generado exitosamente')
    } catch (error) {
      console.error('Error generating PDF:', error)
      toast.error('Error al generar el PDF')
    } finally {
      setIsGeneratingPDF(false)
    }
  }

  // Vista de no autorizado
  if (!isDocente) {
    return (
      <ProtectedRoute>
        <div className='flex min-h-screen items-center justify-center'>
          <Card className='max-w-md'>
            <CardContent className='flex flex-col items-center justify-center py-12'>
              <Users className='mb-4 h-12 w-12 text-muted-foreground' />
              <h3 className='mb-2 text-lg font-semibold'>Acceso Restringido</h3>
              <p className='text-center text-muted-foreground'>
                Esta página está disponible únicamente para docentes.
              </p>
            </CardContent>
          </Card>
        </div>
      </ProtectedRoute>
    )
  }

  // Vista de carga
  if (isLoading) {
    return (
      <ProtectedRoute>
        <Header>
          <Search />
          <div className='ms-auto flex items-center gap-4'>
            <ProfileDropdown />
          </div>
        </Header>
        <Main>
          <div className='flex h-[60vh] items-center justify-center'>
            <div className='flex flex-col items-center gap-4'>
              <Loader2 className='h-8 w-8 animate-spin text-primary' />
              <p className='text-muted-foreground'>Cargando información...</p>
            </div>
          </div>
        </Main>
      </ProtectedRoute>
    )
  }

  // Vista de no director de grado
  if (!isDirector || !managedGrade) {
    return (
      <ProtectedRoute>
        <Header>
          <Search />
          <div className='ms-auto flex items-center gap-4'>
            <ProfileDropdown />
          </div>
        </Header>
        <Main>
          <div className='flex h-[60vh] items-center justify-center'>
            <Card className='max-w-md'>
              <CardContent className='flex flex-col items-center justify-center py-12'>
                <Users className='mb-4 h-12 w-12 text-muted-foreground' />
                <h3 className='mb-2 text-lg font-semibold'>
                  No eres Director de Grado
                </h3>
                <p className='text-center text-muted-foreground'>
                  Esta función está disponible únicamente para docentes que son
                  directores de grado.
                </p>
                <p className='mt-4 text-sm text-muted-foreground'>
                  Si crees que deberías ser director de grado, contacta al
                  administrador.
                </p>
              </CardContent>
            </Card>
          </div>
        </Main>
      </ProtectedRoute>
    )
  }

  // Vista del formulario del estudiante seleccionado
  if (selectedStudent && report) {
    return (
      <ProtectedRoute>
        <Header>
          <Search />
          <div className='ms-auto flex items-center gap-4'>
            <ProfileDropdown />
          </div>
        </Header>
        <Main>
          <div className='mx-auto max-w-4xl space-y-6'>
            {/* Header */}
            <div className='flex items-center justify-between'>
              <div className='flex items-center gap-4'>
                <Button
                  variant='outline'
                  size='sm'
                  onClick={handleBackToStudents}
                >
                  <ChevronLeft className='mr-2 h-4 w-4' />
                  Volver
                </Button>
                <div>
                  <h1 className='text-2xl font-bold tracking-tight'>
                    Informe Individual
                  </h1>
                  <p className='text-muted-foreground'>
                    {selectedStudent.name} {selectedStudent.last_name} -{' '}
                    {managedGrade.name}
                  </p>
                </div>
              </div>
              <div className='flex items-center gap-4'>
                {/* Selector de período */}
                <div className='flex items-center gap-2'>
                  <label className='text-sm font-medium text-muted-foreground'>
                    Período:
                  </label>
                  <select
                    value={selectedPeriod}
                    onChange={(e) => handlePeriodChange(e.target.value)}
                    className='h-9 rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm focus:ring-1 focus:ring-ring focus:outline-none'
                  >
                    <option value='1'>Período 1</option>
                    <option value='2'>Período 2</option>
                    <option value='3'>Período 3</option>
                    <option value='4'>Período 4</option>
                  </select>
                </div>
                <Button
                  variant='outline'
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPDF}
                >
                  {isGeneratingPDF ? (
                    <Loader2 className='mr-2 h-4 w-4 animate-spin' />
                  ) : (
                    <Download className='mr-2 h-4 w-4' />
                  )}
                  Exportar PDF
                </Button>
              </div>
            </div>

            <Separator />

            {/* Información del grado (solo lectura) */}
            <Card>
              <CardHeader>
                <CardTitle className='text-sm font-medium text-muted-foreground'>
                  Información del Grado
                </CardTitle>
              </CardHeader>
              <CardContent className='grid gap-4 sm:grid-cols-2'>
                <div>
                  <label className='text-sm font-medium'>Grado</label>
                  <p className='text-lg font-semibold'>{managedGrade.name}</p>
                </div>
                <div>
                  <label className='text-sm font-medium'>Nivel</label>
                  <p className='text-lg font-semibold'>{managedGrade.level}</p>
                </div>
              </CardContent>
            </Card>

            {/* Tabla de observaciones por materia */}
            <Card>
              <CardHeader>
                <CardTitle className='flex items-center gap-2'>
                  <BookOpen className='h-5 w-5' />
                  Observaciones por Materia
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className='overflow-x-auto'>
                  <table className='w-full border-collapse border border-gray-300'>
                    {/* Header */}
                    <thead>
                      <tr className='bg-gray-50'>
                        <th
                          rowSpan={2}
                          className='w-32 border border-gray-300 px-2 py-3 text-center text-xs font-semibold uppercase'
                        >
                          Asignatura
                        </th>
                        <th
                          colSpan={3}
                          className='border border-gray-300 px-2 py-2 text-center text-xs font-semibold uppercase'
                        >
                          Observaciones Académicas
                        </th>
                        <th
                          colSpan={3}
                          className='border border-gray-300 px-2 py-2 text-center text-xs font-semibold uppercase'
                        >
                          Comportamental
                        </th>
                        <th
                          rowSpan={2}
                          className='w-40 border border-gray-300 px-2 py-3 text-center text-xs font-semibold uppercase'
                        >
                          Observaciones del Docente
                        </th>
                      </tr>
                      <tr className='bg-gray-50'>
                        <th className='w-28 border border-gray-300 px-2 py-2 text-center text-xs font-medium'>
                          ACTIVIDADES PENDIENTES
                        </th>
                        <th className='w-28 border border-gray-300 px-2 py-2 text-center text-xs font-medium'>
                          ACTIVIDADES INSUFICIENTES
                        </th>
                        <th className='w-28 border border-gray-300 px-2 py-2 text-center text-xs font-medium'>
                          NOTAS POSITIVAS
                        </th>
                        <th className='w-20 border border-gray-300 px-2 py-2 text-center text-xs font-medium'>
                          PROBL. CONVIVENCIA
                        </th>
                        <th className='w-16 border border-gray-300 px-2 py-2 text-center text-xs font-medium'>
                          FALTAS/TARDE
                        </th>
                        <th className='w-24 border border-gray-300 px-2 py-2 text-center text-xs font-medium'>
                          PRESENTACIÓN
                        </th>
                      </tr>
                    </thead>
                    {/* Body */}
                    <tbody>
                      {report.observations.map((obs) => (
                        <tr key={obs.subjectId} className='hover:bg-gray-50/50'>
                          <td className='border border-gray-300 px-2 py-2 align-middle'>
                            <span className='text-xs font-medium'>
                              {obs.subjectName}
                            </span>
                          </td>
                          <td className='border border-gray-300 p-1 align-top'>
                            <textarea
                              value={obs.pendingActivities}
                              onChange={(e) =>
                                handleUpdateSubjectObservation(
                                  obs.subjectId,
                                  'pendingActivities',
                                  e.target.value
                                )
                              }
                              className='min-h-[50px] w-full resize-none border-0 bg-transparent p-1 text-[10px] focus:ring-0 focus:outline-none'
                              placeholder='Sin actividades pendientes'
                            />
                          </td>
                          <td className='border border-gray-300 p-1 align-top'>
                            <textarea
                              value={obs.insufficientActivities}
                              onChange={(e) =>
                                handleUpdateSubjectObservation(
                                  obs.subjectId,
                                  'insufficientActivities',
                                  e.target.value
                                )
                              }
                              className='min-h-[50px] w-full resize-none border-0 bg-transparent p-1 text-[10px] focus:ring-0 focus:outline-none'
                              placeholder='Sin actividades insuficientes'
                            />
                          </td>
                          <td className='border border-gray-300 p-1 align-top'>
                            <textarea
                              value={obs.positiveNotes}
                              onChange={(e) =>
                                handleUpdateSubjectObservation(
                                  obs.subjectId,
                                  'positiveNotes',
                                  e.target.value
                                )
                              }
                              className='min-h-[50px] w-full resize-none border-0 bg-transparent p-1 text-[10px] focus:ring-0 focus:outline-none'
                              placeholder='Sin notas positivas'
                            />
                          </td>
                          <td className='border border-gray-300 px-2 py-2 text-center align-middle'>
                            <span
                              className={`text-xs font-medium ${obs.behavioralIssues === 'Sí' ? 'text-red-600' : 'text-green-600'}`}
                            >
                              {obs.behavioralIssues}
                            </span>
                          </td>
                          <td className='border border-gray-300 px-2 py-2 text-center align-middle'>
                            <span
                              className={`text-xs font-medium ${obs.attendanceIssues === 'Sí' ? 'text-red-600' : 'text-green-600'}`}
                            >
                              {obs.attendanceIssues}
                            </span>
                          </td>
                          <td className='border border-gray-300 px-2 py-1 align-middle'>
                            <span className='text-xs'>
                              {obs.personalPresentation || 'Adecuada'}
                            </span>
                          </td>
                          <td className='border border-gray-300 p-1 align-top'>
                            <textarea
                              value={obs.teacherObservation}
                              onChange={(e) =>
                                handleUpdateSubjectObservation(
                                  obs.subjectId,
                                  'teacherObservation',
                                  e.target.value
                                )
                              }
                              className='min-h-[50px] w-full resize-none border-0 bg-transparent p-1 text-[10px] focus:ring-0 focus:outline-none'
                              placeholder='Sin observaciones'
                            />
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
                {(!report.observations || report.observations.length === 0) && (
                  <div className='flex flex-col items-center justify-center py-8 text-muted-foreground'>
                    <BookOpen className='mb-2 h-8 w-8' />
                    <p>No hay materias asignadas a este grado.</p>
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Observaciones generales / Actitudinal */}
            <Card>
              <CardHeader className='pb-2'>
                <CardTitle className='text-sm font-semibold tracking-wide uppercase'>
                  OBSERVACIONES/ ACTITUDINAL
                </CardTitle>
              </CardHeader>
              <CardContent>
                <textarea
                  value={report.generalObservations}
                  onChange={(e) =>
                    setReport({
                      ...report,
                      generalObservations: e.target.value,
                    })
                  }
                  className='min-h-[100px] w-full resize-none rounded-md border border-gray-300 bg-white p-3 text-sm focus:border-primary focus:ring-1 focus:ring-primary focus:outline-none'
                  placeholder='Ingrese las observaciones generales o actitudinales del estudiante...'
                />
              </CardContent>
            </Card>

            {/* Botones de acción */}
            <div className='flex justify-end gap-4'>
              <Button variant='outline' onClick={handleBackToStudents}>
                Cancelar
              </Button>
              <Button onClick={handleSaveReport}>Guardar Informe</Button>
            </div>
          </div>
        </Main>
      </ProtectedRoute>
    )
  }

  // Vista de lista de estudiantes (cards)
  return (
    <ProtectedRoute>
      <Header>
        <Search />
        <div className='ms-auto flex items-center gap-4'>
          <ProfileDropdown />
        </div>
      </Header>
      <Main>
        <div className='space-y-6'>
          {/* Header */}
          <div>
            <h1 className='text-2xl font-bold tracking-tight'>
              Informe Individual de Estudiantes
            </h1>
            <p className='text-muted-foreground'>
              Grado: <span className='font-semibold'>{managedGrade.name}</span>{' '}
              | Selecciona un estudiante para generar su informe
            </p>
          </div>

          <Separator />

          {/* Grid de estudiantes */}
          {students.length === 0 ? (
            <Card>
              <CardContent className='flex flex-col items-center justify-center py-12'>
                <Users className='mb-4 h-12 w-12 text-muted-foreground' />
                <h3 className='mb-2 text-lg font-semibold'>
                  No hay estudiantes
                </h3>
                <p className='text-center text-muted-foreground'>
                  No se encontraron estudiantes activos en este grado.
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className='grid gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4'>
              {students.map((student) => (
                <Card
                  key={student.id}
                  className='cursor-pointer transition-shadow hover:shadow-md'
                  onClick={() => handleSelectStudent(student)}
                >
                  <CardContent className='p-6'>
                    <div className='flex items-start justify-between'>
                      <div className='flex items-center gap-3'>
                        <div className='flex h-10 w-10 items-center justify-center rounded-full bg-primary/10'>
                          <Users className='h-5 w-5 text-primary' />
                        </div>
                        <div>
                          <h3 className='font-semibold'>
                            {student.name} {student.last_name}
                          </h3>
                          <p className='text-sm text-muted-foreground'>
                            Click para generar informe
                          </p>
                        </div>
                      </div>
                      <Button variant='ghost' size='sm' className='shrink-0'>
                        <FileText className='h-4 w-4' />
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </div>
      </Main>
    </ProtectedRoute>
  )
}
